parameters.command:
=set -eu

TELEPHELY_ID='{{ $json.body.telephely_id }}'
FLEXI_DOMAIN='{{ $json.body.flexi_domain }}'
FLEXI_USER='{{ $json.body.flexi_username }}'
FLEXI_PW='{{ $json.body.flexi_pw }}'
PACIENS_ID='{{ $json.body.PaciensID }}'

# STDIN-be egy olyan JSON-t adunk, ami tartalmazza:
# - a matcher node teljes kimenetét (benne: parsed -> diagnoses -> BNO)
# - plusz a 3 textbox tartalmát: pap_history / pap_treatments / pap_drugs
MATCHER_JSON='{{ (() => {
  const firstJson = (nodeName) => {
    const its = $items(nodeName);
    if (!its || !its.length) return {};
    return its[0].json || {};
  };

  const m  = firstJson("matcher");
  const a  = firstJson("AI Agent");
  const a1 = firstJson("AI Agent1");
  const a2 = firstJson("AI Agent2");

  const pickText = (o) =>
    (o.pap_history ?? o.pap_treatments ?? o.pap_drugs ?? o.anamnezis ?? o.anamnézis ?? o.kezelesek ?? o.kezelések ?? o.gyogyszerek ?? o.gyógyszerek ??
     o.text ?? o.output ?? o.result ?? o.response ?? o.content ?? "");

  const merged = Object.assign({}, m, {
    pap_history:   (a.pap_history   ?? pickText(a)  ?? ""),
    pap_treatments:(a1.pap_treatments ?? pickText(a1) ?? ""),
    pap_drugs:     (a2.pap_drugs    ?? pickText(a2) ?? ""),
  });

  return JSON.stringify(merged);
})() }}'

SCRIPT_PATH=""

for p in \
  "data/playground/TreatNote/SCRIPTS/ambulans.py" \
  "./data/playground/TreatNote/SCRIPTS/ambulans.py" \
  "/home/node/.n8n/data/playground/TreatNote/SCRIPTS/ambulans.py" \
  "/data/playground/TreatNote/SCRIPTS/ambulans.py"
do
  if [ -f "$p" ]; then
    SCRIPT_PATH="$p"
    break
  fi
done

if [ -z "$SCRIPT_PATH" ]; then
  echo "HIBA: ambulans.py nem található a megadott útvonalakon." >&2
  exit 2
fi

if [ -z "$MATCHER_JSON" ] || [ "$MATCHER_JSON" = "null" ]; then
  echo "HIBA: MATCHER_JSON üres/null. Ellenőrizd, hogy tényleg a matcher + AI Agent node-ok kimenete elérhető-e." >&2
  exit 3
fi

# Unbuffered, hogy minden log azonnal kijojjon
export PYTHONUNBUFFERED=1

# STDIN: összerakott JSON (matcher + 3 szöveg)
printf '%s' "$MATCHER_JSON" | \
python3 "$SCRIPT_PATH" "$TELEPHELY_ID" "$FLEXI_DOMAIN" "$FLEXI_USER" "$FLEXI_PW" "$PACIENS_ID"

