// ==========================================================
// OPTIMIZED BNO MATCHER (Multi-Match Support)
// ==========================================================

// ====== CONFIG ======
const SUPABASE_URL = "https://bpjzgapmoyhtgryglcke.supabase.co";
const SUPABASE_SERVICE_KEY = "sb_secret_gRiwdPwnR3BcA6zo1a8XXQ_Z7bJr8Vn";
const OPENAI_API_KEY = "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";

const EMBEDDING_MODEL = "text-embedding-3-large"; 
const SIMILARITY_THRESHOLD = 0.55;   // Picit még engedékenyebb, hátha a TBC pont beborul 0.58-al
const MATCH_COUNT_PER_CHUNK = 3;     // <-- ITT ÁLLÍTHATOD: Top 3 találatot adjon vissza!
const RPC_NAME = "match_bno_embedding";
const SOURCE_TYPES = ["name", "semantic_description", "text_source"];
const DEBUG = true;
const debug_log = [];

const HTTP_OPTIONS = { timeout: 60000 };

// ====== HELPERS ======
function log(msg, data) {
    if (!DEBUG) return;
    const ts = new Date().toISOString().split("T")[1].replace("Z", "");
    let extra = "";
    if (data !== undefined) {
        try {
            extra = typeof data === "object" ? " | " + JSON.stringify(data).slice(0, 500) : " | " + String(data);
        } catch (e) { extra = " | [unserializable]"; }
    }
    debug_log.push(`[${ts}] ${msg}${extra}`);
}

async function apiCall(name, options) {
    log(`>>> API CALL: ${name}`);
    try {
        const res = await this.helpers.httpRequest({ ...options, ...HTTP_OPTIONS, json: true });
        return res;
    } catch (err) {
        log(`!!! API ERROR: ${name}`, err.message);
        return { __error: err.message };
    }
}

function pickCodeAndLabel(row) {
    const code = row?.code || row?.bno10 || row?.icd10 || row?.bno || null;
    const label = row?.name || row?.text_label || row?.label || row?.megnevezes || null;
    return { code: code ? String(code).toUpperCase() : null, label: label ? String(label) : null };
}

// ====== MAIN ======
const inputItem = $input.first().json;
const parsed = inputItem.parsed || inputItem;

let diagnoses = parsed.diagnoses || [];
if (!Array.isArray(diagnoses)) diagnoses = [];

if (diagnoses.length === 0) {
    parsed._bno_matcher_debug = { log: debug_log, msg: "Nincs diagnózis az 1. node kimenetében." };
    return [{ json: { ...inputItem, parsed } }];
}

// 1) Kiválogatjuk azokat
const toEmbedInfos = [];
diagnoses.forEach((diag, idx) => {
    if (!diag.bno10 || String(diag.bno10).trim() === "") {
        // KICSERÉLT SOR: A teljes sztorit (evidence) húzzuk be!
        const searchText = (diag.evidence || "").trim(); 

        if (searchText.length > 2) {
            toEmbedInfos.push({ idx, text: searchText });
        }
    }
});

let newDiagnoses = []; // Ebbe építjük bele a bővített, multi-match listát

if (toEmbedInfos.length > 0) {
    const embTexts = toEmbedInfos.map(t => t.text);

    const embRes = await apiCall.call(this, "OpenAI_Embeddings", {
        method: "POST",
        url: "https://api.openai.com/v1/embeddings",
        headers: { Authorization: `Bearer ${OPENAI_API_KEY}` },
        body: { model: EMBEDDING_MODEL, dimensions: 1536, input: embTexts }, // <-- Dimensions 1536 fix!
    });

    if (embRes?.__error || !embRes?.data) {
        parsed._bno_matcher_debug = { error: "OpenAI Failed", log: debug_log };
        newDiagnoses = [...diagnoses]; 
    } else {
        // 3) Supabase RPC
        const rpcPromises = embRes.data.map(item =>
            apiCall.call(this, "Supabase_RPC", {
                method: "POST",
                url: `${SUPABASE_URL}/rest/v1/rpc/${RPC_NAME}`,
                headers: { apikey: SUPABASE_SERVICE_KEY, Authorization: `Bearer ${SUPABASE_SERVICE_KEY}` },
                body: {
                    query_embedding: `[${item.embedding.join(",")}]`,
                    match_threshold: SIMILARITY_THRESHOLD,
                    match_count: MATCH_COUNT_PER_CHUNK, 
                    p_source_types: SOURCE_TYPES,
                }
            })
        );

        const allRpcResults = await Promise.all(rpcPromises);

        // Trackeljük mik azok az indexek, amiket módosítottunk (hogy a végén a kimaradókat visszaadjuk)
        const embeddedIndexes = new Set(toEmbedInfos.map(info => info.idx));

        toEmbedInfos.forEach((info, i) => {
            const res = allRpcResults[i];
            const diagRef = diagnoses[info.idx];

            if (res && !res.__error && Array.isArray(res) && res.length > 0) {
                // Top X találaton végigmegyünk, és mindet egy klónozott diagnózisként mentjük!
                res.forEach(row => {
                    const { code, label } = pickCodeAndLabel(row);
                    if (code) {
                        newDiagnoses.push({
                            ...diagRef, // Eredeti adatok megtartása (text_label, evidence)
                            bno10: code,
                            confidence: Math.round((row.similarity || 0) * 100) / 100,
                            _bno_name: label
                        });
                    }
                });
            } else {
                // Nincs találat egy sem, betesszük módosítatlanul nulla BNO-val
                diagRef.bno10 = null;
                newDiagnoses.push(diagRef);
            }
        });

        // Hozzáadjuk azokat, amiket NEM kellett embeddelni (benne voltak alapból jó BNO-val)
        diagnoses.forEach((diag, idx) => {
            if (!embeddedIndexes.has(idx)) {
                newDiagnoses.push(diag);
            }
        });
    }
} else {
    newDiagnoses = diagnoses;
}

// 5) Eredmény mentése
parsed.diagnoses = newDiagnoses;
parsed._bno_matcher_debug = {
    to_embed_count: toEmbedInfos.length,
    log: debug_log
};

return [{ json: { ...inputItem, parsed } }];

options.systemMessage:
=Te egy általános ambuláns lap “KEZELÉSEK” szekcióját írod meg strukturáltan.
Bemenetként kapsz egy szabad szöveget (beteg–orvos párbeszéd, triázs, vizsgálati jegyzet, lelet).
A cél: a kezelések szekció kitöltése úgy, hogy a kimenet formailag mindig ugyanúgy nézzen ki.

SZABÁLYOK:
- Csak a bemeneti szöveg alapján dolgozz. Ne találj ki semmit.
- Ha valami nem szerepel: írd “nincs adat” vagy “nem ismert”.
- Használj rövid, klinikai stílust. Ne magyarázz hosszan.
- Ha több esemény volt, mindet sorold fel.
- Ha szerepel időpont/dátum, paraméterek, értékek (pl. RR, pulzus), beavatkozás, vizsgálat: írd bele.
- Ha szerepel kontroll / beutalás / további teendő: legyen benne.
- A kimenetben NE legyen semmi más, csak a KEZELÉSEK blokk.


KIMENET (PONTOSAN EZ A FORMA, kitöltve):
KEZELÉSEK:
