// n8n Code node (JS) – minimal, modul nélkül

function pickText(obj) {
  if (!obj || typeof obj !== "object") return "";
  const candidates = [
    obj.output,
    obj.text,
    obj.content,
    obj.answer,
    obj.result,
    obj.response,
    obj.message,
  ];
  for (const v of candidates) {
    if (typeof v === "string" && v.trim()) return v.trim();
  }
  // ha pl. { data: { text: "..." } }
  if (obj.data && typeof obj.data.text === "string" && obj.data.text.trim()) return obj.data.text.trim();
  return "";
}

const anamnezis = pickText($items("AI Agent")?.[0]?.json);
const kezelesek = pickText($items("AI Agent1")?.[0]?.json);
const gyogyszerek = pickText($items("AI Agent2")?.[0]?.json);

